     1→import '@testing-library/jest-native/extend-expect';
     2→import { fireEvent, render, waitFor } from '@testing-library/react-native';
     3→import React from 'react';
     4→import { Linking } from 'react-native';
     5→import { PointsDetailProps } from '../../../src/screens/PointsDetail/Models';
     6→import PointsDetailView from '../../../src/screens/PointsDetail/view';
     7→import { TestProvider } from '../../__mocks__/utils/test-provider';
     8→
     9→jest.mock('react-native', () => {
