    26→      addEventListener: jest.fn(() => ({ remove: jest.fn() })),
    27→    },
    28→  };
    29→});
    30→
    31→jest.mock('@react-navigation/native', () => ({
    32→  useNavigation: jest.fn(() => ({
    33→    navigate: jest.fn(),
    34→    goBack: jest.fn(),
    35→  })),
    36→  useNavigationState: jest.fn(() => 'PointsDetail'),
    37→}));
    38→
    39→jest.mock('react-native-safe-area-context', () => ({
