    48→  eventSelectContent: jest.fn(),
    49→}));
    50→
    51→jest.mock('../../../src/services/moment', () => ({
    52→  moment: jest.fn((date: string) => {
    53→    const mockMoment = {
    54→      format: jest.fn((format: string) => {
    55→        if (format === 'DD') return '15';
    56→        if (format === 'MMM') return 'Jan';
    57→        if (format === 'YYYY') return '2024';
    58→        if (format === 'HH:mm') return '10:30';
    59→        return date;
    60→      }),
    61→    };
    62→    return mockMoment;
    63→  }),
    64→}));
    65→
    66→jest.mock('../../../src/utils/functions', () => ({
    67→  formatToCurrency: jest.fn(
    68→    (value: number) => `R$ ${value.toFixed(2).replace('.', ',')}`,
    69→  ),
    70→}));
    71→
    72→const mockModalizeRef = {
    73→  current: {
    74→    open: jest.fn(),
    75→    close: jest.fn(),
    76→  },
    77→};
    78→
    79→describe('PointsDetailView', () => {
    80→  const mockHandleGoBack = jest.fn();
    81→  const mockHandleOpenReportProblem = jest.fn();
    82→  const mockHandleCloseReportProblem = jest.fn();
    83→  const mockTransaction: PointsDetailProps['transaction'] = {
    84→    id: '1',
    85→    date: '2024-01-15T10:30:00Z',
    86→    description: 'Test Transaction',
    87→    type: 'RECEIVED',
    88→    amount: 1000,
    89→    currencyValue: 50.0,
    90→    icon: 'icon-test',
    91→    details: {
    92→      provider: 'test-provider',
    93→      extraInfo: 'test info',
    94→      fields: [
    95→        {
    96→          label: 'Marca',
    97→          value: 'Toyota',
    98→        },
    99→        {
   100→          label: 'Modelo',
   101→          value: 'Corolla',
   102→        },
   103→        {
   104→          label: 'Placa',
   105→          value: 'ABC-1234',
   106→        },
   107→      ],
   108→    },
   109→  };
   110→
   111→  const defaultProps: PointsDetailProps = {
   112→    handleGoBack: mockHandleGoBack,
   113→    transaction: mockTransaction,
   114→    modalizeRef: mockModalizeRef as any,
   115→    handleOpenReportProblem: mockHandleOpenReportProblem,
   116→    handleCloseReportProblem: mockHandleCloseReportProblem,
   117→  };
   118→
   119→  beforeEach(() => {
   120→    jest.clearAllMocks();
   121→  });
   122→
   123→  it('should render component with transaction data', () => {
   124→    const { getByText } = render(
   125→      <TestProvider>
   126→        <PointsDetailView {...defaultProps} />
   127→      </TestProvider>,
   128→    );
   129→
   130→    expect(getByText('Test Transaction')).toBeTruthy();
   131→    expect(getByText(/\+ 1\.000/)).toBeTruthy();
   132→  });
   133→
   134→  it('should display formatted currency value', () => {
   135→    const { getByText } = render(
   136→      <TestProvider>
   137→        <PointsDetailView {...defaultProps} />
   138→      </TestProvider>,
   139→    );
   140→
   141→    expect(getByText('R$ 50,00')).toBeTruthy();
   142→  });
   143→
   144→  it('should display formatted date in highlight text', () => {
   145→    const { getByText } = render(
   146→      <TestProvider>
   147→        <PointsDetailView {...defaultProps} />
   148→      </TestProvider>,
   149→    );
   150→
   151→    expect(getByText(/Compra feita em/)).toBeTruthy();
   152→  });
   153→
   154→  it('should show negative points for DEBIT type', () => {
   155→    const debitTransaction = {
   156→      ...mockTransaction,
   157→      type: 'DEBIT' as const,
   158→      amount: 500,
   159→    };
   160→
   161→    const { getByText } = render(
   162→      <TestProvider>
   163→        <PointsDetailView {...defaultProps} transaction={debitTransaction} />
   164→      </TestProvider>,
   165→    );
   166→
   167→    expect(getByText(/- 500/)).toBeTruthy();
   168→  });
   169→
   170→  it('should show tag content when gainType is TAG', () => {
   171→    const tagTransaction = {
   172→      ...mockTransaction,
   173→      icon: 'icon-tag',
   174→      description: 'Pedágio',
   175→    };
   176→
   177→    const { getByText } = render(
   178→      <TestProvider>
   179→        <PointsDetailView {...defaultProps} transaction={tagTransaction} />
   180→      </TestProvider>,
   181→    );
   182→
   183→    expect(getByText('Tag')).toBeTruthy();
   184→    expect(getByText('Tipo de compra')).toBeTruthy();
   185→  });
   186→
   187→  it('should open modal when "Relatar Problema" button is pressed', () => {
   188→    const { getByText } = render(
   189→      <TestProvider>
   190→        <PointsDetailView {...defaultProps} />
   191→      </TestProvider>,
   192→    );
   193→
   194→    const reportButton = getByText('Relatar Problema');
   195→    fireEvent.press(reportButton);
   196→
   197→    expect(mockHandleOpenReportProblem).toHaveBeenCalled();
   198→  });
   199→
   200→  it('should open phone link when "Capitais" card is pressed', async () => {
   201→    const { eventSelectContent } = require('~/constants/functions');
   202→
   203→    const { getByText } = render(
   204→      <TestProvider>
   205→        <PointsDetailView {...defaultProps} />
   206→      </TestProvider>,
   207→    );
   208→
   209→    await waitFor(() => {
   210→      const capitasCard = getByText('Capitais');
   211→      fireEvent.press(capitasCard);
   212→
   213→      expect(eventSelectContent).toHaveBeenCalledWith({
   214→        content_type: 'cta',
   215→        content_id: 'telefones_capitais',
   216→        location_1: 'monetizacao',
   217→        location_2: 'hub_recompensas_spmais',
   218→        location_3: 'contato_telefones',
   219→      });
   220→
   221→      expect(Linking.openURL).toHaveBeenCalledWith('tel:40021552');
   222→    });
   223→  });
   224→
   225→  it('should open phone link when "Demais localidades" card is pressed', async () => {
   226→    const { eventSelectContent } = require('~/constants/functions');
   227→
   228→    const { getByText } = render(
   229→      <TestProvider>
   230→        <PointsDetailView {...defaultProps} />
   231→      </TestProvider>,
   232→    );
   233→
   234→    await waitFor(() => {
   235→      const demaisCard = getByText('Demais localidades');
   236→      fireEvent.press(demaisCard);
   237→
   238→      expect(eventSelectContent).toHaveBeenCalledWith({
   239→        content_type: 'cta',
   240→        content_id: 'telefones_demais_localidades',
   241→        location_1: 'monetizacao',
   242→        location_2: 'hub_recompensas_spmais',
   243→        location_3: 'contato_telefones',
